HallManager = {}
HallManager.Queue = {}

function HallManager:addEnterRoomQueue(player)
    EngineUtil.sendEnterOtherGame(player.rakssid, "g1057", player.userId)
    HallManager.Queue[tostring(player.userId)] = {
        rakssid = player.rakssid,
        gameType = "g1057",
        userId = player.userId,
        time = os.time()
    }
end

function HallManager:tryQueueEnterRoom()
    local time = os.time()
    for _, item in pairs(HallManager.Queue) do
        if time - item.time >= 10 then
            EngineUtil.sendEnterOtherGame(item.rakssid, item.gameType, item.userId)
            item.time = time
        end
    end
end

function HallManager:onPlayerLogout(player)
    HallManager.Queue[tostring(player.userId)] = nil
end

return HallManager